using UnityEngine;

/// <summary>
/// Dano por contacto de um inimigo (P3 — consome EnemyData.stats.contactDamage,
/// que até aqui nunca era lido): tocar no corpo do inimigo fere o player,
/// mesmo sem ser um ataque.
///
/// Funciona com collider sólido (OnCollisionStay2D) ou trigger
/// (OnTriggerStay2D). Passa por PlayerCombat.TryDamagePlayer (P2): respeita
/// i-frames, aplica a Defesa da forma e dá knockback. "tickInterval" evita
/// dano contínuo a cada frame (além dos i-frames do próprio player).
///
/// Não aplica dano em estados terminais (Morto/Desactivado) nem Atordoado.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyContactDamage : MonoBehaviour
{
    [Tooltip("Intervalo mínimo (segundos) entre danos de contacto.")]
    [Min(0.1f)] public float tickInterval = 0.6f;

    [Tooltip("Força de empurrão aplicada ao player no contacto.")]
    [Min(0f)] public float contactKnockback = 6f;

    private EnemyController _controller;
    private float _nextDamageTime;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
    }

    private void OnCollisionStay2D(Collision2D collision) => TryHit(collision.collider);
    private void OnTriggerStay2D(Collider2D other) => TryHit(other);

    private void TryHit(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        if (_controller.IsTerminal || _controller.State == EnemyState.Atordoado) return;
        if (Time.time < _nextDamageTime) return;

        int damage = _controller.Data != null ? _controller.Data.stats.contactDamage : 0;
        if (damage <= 0) return;

        if (PlayerCombat.TryDamagePlayer(other.transform, damage, transform.position, contactKnockback))
            _nextDamageTime = Time.time + tickInterval;
    }
}
